async function withTimeout(p,label,ms=10000){return Promise.race([p,new Promise((_,rej)=>setTimeout(()=>rej(Error(`${label}: timeout ${Math.round(ms/1000)}s`)),ms))])}
function sleep(ms){return new Promise(r=>setTimeout(r,ms))}
async function retry(fn,label,attempts=2,delay=1200){let last;for(let i=1;i<=attempts;i++){try{return await fn(i)}catch(e){last=e;if(i<attempts){status('Загрузка',`${label}: повторная попытка ${i+1}/${attempts}...`);await sleep(delay)}}}throw last}
async function required(name,p,ms=12000){let r=await withTimeout(p,name,ms);if(r.error)throw Error(name+': '+r.error.message);return r.data||[]}
async function optional(name,p,ms=6500){try{let r=await withTimeout(p,name,ms);if(r.error){S.warnings.push(name+': '+r.error.message);return[]}return r.data||[]}catch(e){S.warnings.push(name+': '+(e.message||e));return[]}}
async function paged(table,queryFactory,{page=350,max=3000,ms=9000,label=table}={}){let out=[];for(let from=0;from<max;from+=page){let to=from+page-1;let q=queryFactory().range(from,to);let r=await withTimeout(q,`${label} ${from}-${to}`,ms);if(r.error)throw Error(label+': '+r.error.message);let rows=r.data||[];out.push(...rows);status('Загрузка',`Читаю ${label}: ${out.length}...`);if(rows.length<page)break}return out}
async function loadTasksSafe(){S.tasksLoading=true;S.taskError='';render();try{let rows=await retry(()=>paged('tasks',()=>S.sb.from('tasks').select(TASK_COLUMNS).is('deleted_at',null).order('created_at',{ascending:true}),{page:200,max:3000,ms:30000,label:'tasks'}),'tasks',2,1600);S.tasks=rows;S.taskError='';return S.tasks}catch(e){S.taskError=e.message||String(e);S.warnings.push('tasks: '+S.taskError);status('Задачи не загрузились',`${S.taskError}. Проекты и остальные разделы не блокируются.`);return S.tasks||[]}finally{S.tasksLoading=false;render()}}
async function restore(){sb();let s=await S.sb.auth.getSession();S.user=s.data?.session?.user||null;if(!S.user){let u=await S.sb.auth.getUser();S.user=u.data?.user||null}if(!S.user){S.profile=null;if($('authState'))$('authState').textContent='Auth: не выполнен вход';return null}let p=await optional('profile/auth_user_id',S.sb.from('app_users').select('*').eq('auth_user_id',S.user.id).maybeSingle(),8000);p=Array.isArray(p)?null:p;if((!p)&&S.user.email){let e=await optional('profile/email',S.sb.from('app_users').select('*').eq('email',S.user.email).maybeSingle(),8000);p=Array.isArray(e)?null:e;if(p&&!p.auth_user_id)S.sb.from('app_users').update({auth_user_id:S.user.id}).eq('id',p.id).then(()=>0)}S.profile=p||null;if($('authState'))$('authState').textContent=S.profile?`Auth: ${S.user.email} · ${S.profile.display_name} · ${S.profile.role}`:`Auth: ${S.user.email} · профиль не привязан`;return S.user}
async function load(){if(S.loading)return;S.loading=true;try{await restore();if(!S.user)throw Error('Сначала войдите по email и паролю');if(!S.profile)throw Error('Профиль workspace не найден. Нажмите «Привязать профиль».');S.warnings=[];if(!S.users.length)S.users=[S.profile];status('Загрузка','Читаю projects...');S.projects=(await required('projects',S.sb.from('projects').select('*').order('created_at',{ascending:true}),12000)).filter(x=>!x.deleted_at);render();await loadTasksSafe();status('Загрузка','Читаю справочники...');let users=await optional('app_users',S.sb.from('app_users').select('*').eq('is_active',true).order('created_at',{ascending:true}),7000);if(users.length)S.users=users;S.members=await optional('project_members',S.sb.from('project_members').select('*').order('created_at',{ascending:true}),6000);S.assignees=await optional('task_assignees',S.sb.from('task_assignees').select('*').order('created_at',{ascending:true}),6000);S.subtasks=await optional('task_subtasks',S.sb.from('task_subtasks').select('*').order('created_at',{ascending:true}),6000);S.messages=await optional('project_messages',S.sb.from('project_messages').select('*').order('created_at',{ascending:true}),6000);S.logs=owner()?await optional('activity_log',S.sb.from('activity_log').select('*').order('created_at',{ascending:false}).limit(500),7000):[];if(!S.activeChat&&S.projects[0])S.activeChat=S.projects[0].id;render();status('Подключено',`${S.profile.display_name||S.user.email} · ${S.profile.role} · проектов: ${S.projects.length} · задач: ${S.tasks.length}${S.taskError?' · задачи не обновились':''}${S.warnings.length?' · предупреждения: '+S.warnings.length:''}`)}catch(e){status('Ошибка загрузки базы',e.message||String(e))}finally{S.loading=false}}
function vals(id){let e=$(id);if(!e)return['all'];let v=[...e.selectedOptions].map(o=>o.value).filter(Boolean);if(!v.length)v=[e.value||'all'];return v.includes('all')?['all']:v}function opts(id,html){let e=$(id);if(!e)return;let keep=e.multiple?[...e.selectedOptions].map(o=>o.value):[e.value];e.innerHTML=html;[...e.options].forEach(o=>{o.selected=keep.includes(o.value)});if(!e.multiple&&[...e.options].some(o=>o.value===keep[0]))e.value=keep[0]}
function selects(){let us='<option value="">Не назначен</option>'+S.users.map(u=>`<option value="${u.id}">${esc(u.display_name||u.email)}</option>`).join(''),ps=S.projects.map(p=>`<option value="${p.id}">${esc(p.name)}</option>`).join('');opts('projectOwner',us);opts('taskAssignee',S.users.map(u=>`<option value="${u.id}">${esc(u.display_name||u.email)}</option>`).join(''));opts('taskProject',ps);opts('projectOwnerFilter','<option value="all">Все владельцы</option>'+S.users.map(u=>`<option value="${u.id}">${esc(u.display_name||u.email)}</option>`).join(''));opts('taskProjectFilter','<option value="all">Все проекты</option>'+ps);opts('taskAssigneeFilter','<option value="all">Все исполнители</option>'+S.users.map(u=>`<option value="${u.id}">${esc(u.display_name||u.email)}</option>`).join(''));opts('accessUser',S.users.map(u=>`<option value="${u.id}">${esc(u.display_name||u.email)}</option>`).join(''));opts('chatProject',S.projects.map(p=>`<option value="${p.id}">${esc(p.name)}</option>`).join(''))}
function cardP(p){let all=S.tasks.filter(t=>t.project_id===p.id),pg=Math.round((all.filter(t=>t.status==='done').length||0)/Math.max(1,all.length)*100),c=p.color||'#64748b';return`<article class="project-card" style="--project-bg:${rgba(c,.12)};border-top:4px solid ${c}"><div class="project-title"><div><h4>${esc(p.name)}</h4><div class="row"><span class="badge">${ST[p.status]||p.status||'—'}</span><span class="badge">${PR[p.priority]||p.priority||'—'}</span></div></div><span style="width:14px;height:14px;border-radius:50%;background:${c};display:inline-block"></span></div><p class="muted">${esc(p.description||'Без описания')}</p><p><b>Следующий шаг:</b> ${esc(p.next_step||'—')}</p><p class="muted">Владелец: ${esc(uname(p.owner_id))}</p><p class="muted">${fmt(p.start_date)} → ${fmt(p.deadline)}</p><div class="progress"><i style="width:${pg}%"></i></div><div class="actions"><button class="btn sm secondary" data-action="open-project" data-id="${p.id}">Редактировать</button><button class="btn sm primary" data-action="new-task" data-project-id="${p.id}">+ Задача</button><button class="btn sm secondary" data-action="open-access" data-id="${p.id}">Участники</button><button class="btn sm danger" data-action="delete-project" data-id="${p.id}">Удалить</button></div></article>`}
function subBlock(t){let l=subs(t.id),done=l.filter(x=>x.is_done).length,pct=l.length?Math.round(done/l.length*100):0,c=pcolor(t.project_id);return`<div class="wk-sub" style="--pct:${pct}%;--accent:${c}"><div class="wk-subh"><b>Подзадачи</b><span>${done}/${l.length} · ${pct}%</span></div><div class="wk-subbar"><i></i></div>${l.map(s=>`<label class="wk-subrow ${s.is_done?'done':''}"><input type="checkbox" data-action="toggle-subtask" data-id="${s.id}" ${s.is_done?'checked':''}><span>${esc(s.title)}</span><button type="button" data-action="delete-subtask" data-id="${s.id}">×</button></label>`).join('')||'<div class="muted">Подзадач пока нет.</div>'}<form class="wk-subadd" data-action="add-subtask" data-task-id="${t.id}"><input class="input" name="title" placeholder="Добавить подзадачу"><button type="submit">+</button></form></div>`}
function doneWho(t){let uid=t.completed_by_id||t.completed_by||t.closed_by_id||t.updated_by;return t.status==='done'?`<p class="muted done-meta">Завершено: ${dt(t.completed_at||t.updated_at)} · кем: ${esc(uid?uname(uid):'—')}</p>`:''}
function cardT(t){let over=t.status!=='done'&&t.due_date&&t.due_date<today(),ids=tids(t).map(uname).join(', ')||'Не назначено';return`<article class="task-card wk-task ${t.status==='done'?'wk-complete':''} ${over?'overdue':''}" draggable="true" data-task-id="${t.id}" style="--accent:${pcolor(t.project_id)};--bg:${rgba(pcolor(t.project_id),.12)};--bd:${rgba(pcolor(t.project_id),.34)}"><label class="wk-done"><input type="checkbox" data-action="toggle-task" data-id="${t.id}" ${t.status==='done'?'checked':''}><span></span></label><div class="row"><span class="badge">${PR[t.priority]||t.priority||'—'}</span>${over?'<span class="badge high">Просрочено</span>':''}</div><h4>${esc(t.title)}</h4><p>${esc(pname(t.project_id))}</p><p class="muted">${fmt(t.start_date)} → ${fmt(t.due_date)}</p><p class="muted">${esc(ids)}</p>${t.notes?`<p>${esc(t.notes)}</p>`:''}${doneWho(t)}${subBlock(t)}<div class="actions"><button class="btn sm secondary" data-action="open-task" data-id="${t.id}">Редактировать</button><button class="btn sm danger" data-action="delete-task" data-id="${t.id}">Убрать</button></div></article>`}
function render(){selects();qa('.admin-only').forEach(x=>x.classList.toggle('hidden',!admin()));let audit=document.querySelector('.nav [data-view="audit"]');if(audit)audit.style.display=owner()?'':'none';$('mProjects')&&($('mProjects').textContent=S.projects.length);$('mOpen')&&($('mOpen').textContent=S.tasks.filter(t=>t.status!=='done').length);$('mOverdue')&&($('mOverdue').textContent=S.tasks.filter(t=>t.status!=='done'&&t.due_date&&t.due_date<today()).length);$('mUsers')&&($('mUsers').textContent=S.users.length);$('overviewProjects')&&($('overviewProjects').innerHTML=S.projects.length?S.projects.slice(0,8).map(cardP).join(''):'<div class="empty">Нет загруженных проектов</div>');$('focusList')&&($('focusList').innerHTML=(S.tasks.filter(t=>t.status!=='done').slice(0,8).map(cardT).join('')||'<div class="empty">Нет открытых задач</div>'));if(S.view==='projects')renderProjects();if(S.view==='tasks')renderTasks();if(S.view==='team')renderTeam();if(S.view==='audit')renderAudit();if(S.view==='timeline')renderTimeline();if(S.view==='chat')renderChat();renderAccess()}
