function ensureChatTools(){let p=document.querySelector('#chat .chat-panel');if(!p)return;if(!$('chatSearch')){let head=p.querySelector('.panel-head'),div=document.createElement('div');div.className='chat-tools';div.innerHTML='<input class="input" id="chatSearch" placeholder="Поиск по чату"><button class="btn secondary" id="clearChatBtn" type="button">Очистить чат</button>';(head||p).insertAdjacentElement('afterend',div);$('chatSearch').addEventListener('input',renderChat);$('clearChatBtn').onclick=()=>clearChat().catch(x=>alert(x.message||x))}ensureChatComposer()}
