async function moveTask(id,st){let t=byId(S.tasks,id),old=t?{...t}:null;if(t){t.status=st;if(st==='done'){t.completed_at=new Date().toISOString();t.completed_by_id=S.profile?.id}else{t.completed_at=null;t.completed_by_id=null}renderTasks();if(S.view==='timeline')renderTimeline()}let row={status:st,completed_at:st==='done'?new Date().toISOString():null};let r=await S.sb.from('tasks').update({...row,completed_by_id:st==='done'?S.profile?.id:null}).eq('id',id);if(r.error)r=await S.sb.from('tasks').update(row).eq('id',id);if(r.error){if(old&&t)Object.assign(t,old);renderTasks();throw Error(r.error.message)}}
async function updateTaskTimeline(id,start_date,due_date){let t=byId(S.tasks,id),old=t?{...t}:null;if(t){t.start_date=start_date;t.due_date=due_date;if(S.view==='timeline')renderTimeline()}let r=await S.sb.from('tasks').update({start_date,due_date}).eq('id',id);if(r.error){if(old&&t)Object.assign(t,old);if(S.view==='timeline')renderTimeline();throw Error(r.error.message)}}
async function addSubtask(task_id,title){let r=await S.sb.from('task_subtasks').insert({task_id,title,created_by:S.profile?.id,sort_order:subs(task_id).length}).select().single();if(r.error)throw Error(r.error.message);S.subtasks.push(r.data);render()}
