async function deleteSubtask(id){let r=await S.sb.from('task_subtasks').update({deleted_at:new Date().toISOString()}).eq('id',id);if(r.error)r=await S.sb.from('task_subtasks').delete().eq('id',id);if(r.error)throw Error(r.error.message);S.subtasks=S.subtasks.filter(x=>x.id!==id);render()}
async function uploadChatFiles(project_id){let input=$('chatFiles'),files=[...(input?.files||[])];if(!files.length)return[];let out=[];for(let file of files){let safe=(file.name||'file').replace(/[^a-zA-Z0-9._-]+/g,'_').slice(-90),path=`${project_id}/${Date.now()}_${Math.random().toString(36).slice(2)}_${safe}`;let up=await S.sb.storage.from(BUCKET).upload(path,file,{cacheControl:'3600',upsert:false,contentType:file.type||undefined});if(up.error)throw Error(`Не удалось загрузить файл «${file.name}»: ${up.error.message}`);let pub=S.sb.storage.from(BUCKET).getPublicUrl(path).data?.publicUrl||'';let signed=await S.sb.storage.from(BUCKET).createSignedUrl(path,60*60*24*30);let url=signed?.data?.signedUrl||pub;out.push({name:file.name,url,type:file.type,isImage:(file.type||'').startsWith('image/')})}return out}
async function sendChat(){let project_id=$('chatProject')?.value||S.activeChat,txt=($('chatText')?.value||'').trim();if(!project_id)return;let btn=$('sendChatBtn');if(btn){btn.disabled=true;btn.textContent='...'}try{let files=await uploadChatFiles(project_id),fileLines=files.map(f=>`${f.isImage?'🖼':'📎'} ${f.name}: ${f.url}`);let body=[txt,fileLines.join('\n')].filter(Boolean).join('\n\n');if(!body)return;let r=await S.sb.from('project_messages').insert({project_id,body,author_id:S.profile?.id}).select().single();if(r.error)throw Error(r.error.message);S.messages.push(r.data);$('chatText')&&($('chatText').value='');if($('chatFiles'))$('chatFiles').value='';if($('chatFileSummary'))$('chatFileSummary').textContent='';S.activeChat=project_id;renderChat()}finally{if(btn){btn.disabled=false;btn.textContent='Отправить'}}}
async function deleteMessage(id){let m=byId(S.messages,id);if(m)m.deleted_at=new Date().toISOString();renderChat();let r=await S.sb.from('project_messages').update({deleted_at:new Date().toISOString()}).eq('id',id);if(r.error)r=await S.sb.from('project_messages').delete().eq('id',id);if(r.error)throw Error(r.error.message)}
async function clearChat(){let pid=$('chatProject')?.value||S.activeChat;if(!pid)return;if(!confirm('Очистить сообщения выбранного чата?'))return;S.messages.forEach(m=>{if(m.project_id===pid)m.deleted_at=new Date().toISOString()});renderChat();let r=await S.sb.from('project_messages').update({deleted_at:new Date().toISOString()}).eq('project_id',pid);if(r.error)r=await S.sb.from('project_messages').delete().eq('project_id',pid);if(r.error)throw Error(r.error.message)}
async function signIn(){let email=$('loginEmail')?.value.trim(),pass=$('loginPassword')?.value||'';if(!email||!pass)return alert('Введите email и пароль');status('Вход','Проверяю email и пароль...');let r=await sb().auth.signInWithPassword({email,password:pass});if(r.error)throw Error(r.error.message);await restore();await load()}
async function claim(){await restore();if(!S.user)return alert('Сначала войдите');let r=await S.sb.from('app_users').select('*').eq('email',S.user.email).maybeSingle();if(r.error)throw Error(r.error.message);if(!r.data)throw Error('Профиль с таким email не найден');await S.sb.from('app_users').update({auth_user_id:S.user.id}).eq('id',r.data.id);await restore();await load()}
