(()=>{if(window.__TIMELINE_DYNAMIC_LANES_V104__)return;window.__TIMELINE_DYNAMIC_LANES_V104__=1;const TOP=8,XG=8,YG=14,MH=70,BOT=32;const num=v=>parseFloat(String(v||'').replace('px',''))||0;function tl(){return document.querySelector('.wk-tl')}function css(){if(document.getElementById('tl-lanes-v104-css'))return;let s=document.createElement('style');s.id='tl-lanes-v104-css';s.textContent='.wk-tlitem{box-sizing:border-box!important;height:auto!important;max-height:none!important;min-height:70px!important}.wk-tlitem .wk-tltitle,.wk-tlitem h4,.wk-tlitem .wk-tlmeta{white-space:normal!important;word-break:break-word!important;overflow-wrap:anywhere!important;max-height:none!important}';document.head.appendChild(s)}function mh(el){let cs=getComputedStyle(el),h=num(cs.paddingTop)+num(cs.paddingBottom)+6,t=el.querySelector('.wk-tltitle')||el.querySelector('h4'),m=el.querySelector('.wk-tlmeta');if(t)h+=t.scrollHeight;if(m)h+=m.scrollHeight;return Math.ceil(Math.max(MH,el.scrollHeight,el.offsetHeight,h))}let raf=0;function run(){raf=0;css();let w=tl(),b=w&&w.querySelector('.wk-tlbody');if(!w||!b)return;let keepL=w.scrollLeft,keepT=w.scrollTop,els=[...b.querySelectorAll('.wk-tlitem')];if(!els.length)return;let items=els.map((el,i)=>{el.style.height='auto';let l=num(el.style.left)||el.offsetLeft,wd=num(el.style.width)||el.offsetWidth;return{el,i,l,r:l+wd,t:num(el.style.top)||el.offsetTop,h:mh(el)}}).sort((a,b)=>a.l-b.l||a.r-b.r||a.t-b.t||a.i-b.i),lanes=[];items.forEach(it=>{let n=lanes.findIndex(x=>it.l>=x.r+XG);if(n<0){n=lanes.length;lanes.push({r:-1e9,h:MH})}lanes[n].r=Math.max(lanes[n].r,it.r);lanes[n].h=Math.max(lanes[n].h,it.h);it.n=n});let y=TOP,off=[];lanes.forEach((x,i)=>{off[i]=y;y+=Math.max(MH,x.h)+YG});items.forEach(it=>{let h=Math.ceil(Math.max(MH,it.h));it.el.style.top=(off[it.n]||TOP)+'px';it.el.style.height=h+'px';it.el.style.minHeight=h+'px';it.el.dataset.dynamicLane=String(it.n)});b.style.height=Math.max(360,y+BOT)+'px';w.scrollLeft=keepL;w.scrollTop=keepT}function sch(){if(!raf)raf=requestAnimationFrame(run)}css();new MutationObserver(sch).observe(document.body,{childList:true,subtree:true});document.addEventListener('DOMContentLoaded',sch);window.addEventListener('resize',sch);document.addEventListener('pointerup',sch,true);document.addEventListener('drop',sch,true);setInterval(()=>{if(tl())sch()},700);sch()})();
